class Solution(object):
    def increasingBST(self, root):
        self.prev = None
        def inorder(node):
            if not node:
                return None
            left = inorder(node.left)
            node.left = None
            if self.prev:
                self.prev.right = node
            self.prev = node
            right = inorder(node.right)
            return left if left else node
        return inorder(root)
